reNumber":24,"keyFifths":0},{"startBeat":96,"durationBeats":4,"chordName":"","voicing":[],"measureNumber":25,"keyFifths":0},{"startBeat":100,"durationBeats":2,"chordName":"Dm7","voicing":[48,53,57,64],"voicingNames":["C3","F3","A3","E4"],"voicing_staves":[2,2,2,1],"measureNumber":26,"keyFifths":0},{"startBeat":102,"durationBeats":2,"chordName":"G7","voicing":[47,53,57,64],"voicingNames":["B2","F3","A3","E4"],"voicing_staves":[2,2,2,1],"measureNumber":26,"keyFifths":0},{"startBeat":104,"durationBeats":4,"chordName":"CM7","voicing":[47,52,55,62],"voicingNames":["B2","E3","G3","D4"],"voicing_staves":[2,2,2,1],"measureNumber":27,"keyFifths":0},{"startBeat":108,"durationBeats":2,"chordName":"Dm7","voicing":[48,53,57,64],"voicingNames":["C3","F3","A3","E4"],"voicing_staves":[2,2,2,1],"measureNumber":28,"keyFifths":0},{"startBeat":110,"durationBeats":2,"chordName":"G7","voicing":[47,53,57,64],"voicingNames":["B2","F3","A3","E4"],"voicing_staves":[2,2,2,1],"measureNumber":28,"keyFifths":0},{"startBeat":112,"durationBeats":4,"chordName":"CM7","voicing":[47,52,55,62],"voicingNames":["B2","E3","G3","D4"],"voicing_staves":[2,2,2,1],"measureNumber":29,"keyFifths":0},{"startBeat":116,"durationBeats":2,"chordName":"Dm7","voicing":[48,53,57,64],"voicingNames":["C3","F3","A3","E4"],"voicing_staves":[2,2,2,1],"measureNumber":30,"keyFifths":0},{"startBeat":118,"durationBeats":2,"chordName":"G7","voicing":[47,53,57,64],"voicingNames":["B2","F3","A3","E4"],"voicing_staves":[2,2,2,1],"measureNumber":30,"keyFifths":0},{"startBeat":120,"durationBeats":4,"chordName":"CM7","voicing":[47,52,55,62],"voicingNames":["B2","E3","G3","D4"],"voicing_staves":[2,2,2,1],"measureNumber":31,"keyFifths":0}],"lines":[{"ja":"まずはクローズド・ボイシングじゃ。ルートは抜いて、コードの中身を近くに集める。","en":"First, a closed voicing. Omit the root and gather the chord tones close together.","speaker":"jajii","startBeat":0,"durationBeats":4},{"ja":"Dm7は、3・5・7・9。F、A、C、Eじゃ。","en":"Dm7 is 3, 5, 7, 9. F, A, C, E.","speaker":"jajii","startBeat":4,"durationBeats":4},{"ja":"G7は、7・9・3・13。F、A、B、Eじゃ。","en":"G7 is 7, 9, 3, 13. F, A, B, E.","speaker":"jajii","startBeat":8,"durationBeats":4},{"ja":"CM7は、3・5・7・9。E、G、B、Dじゃ。","en":"CM7 is 3, 5, 7, 9. E, G, B, D.","speaker":"jajii","startBeat":12,"durationBeats":4},{"ja":"では Dm7 に戻るぞい。この、上から2番目の C を見るんじゃ。","en":"Now back to Dm7. Look at the C, the second note from the top.","speaker":"jajii","startBeat":16,"durationBeats":2},{"ja":"その C を、1オクターブ下に落とす。","en":"Drop that C down one octave.","speaker":"jajii","startBeat":18,"durationBeats":2},{"ja":"これが Dm7 の Drop2 じゃ。C、F、A、E。","en":"This is Dm7 Drop 2. C, F, A, E.","speaker":"jajii","startBeat":20,"durationBeats":4},{"ja":"理屈を増やしすぎるな。上から2番目を落とす。それだけじゃ。","en":"Do not overthink it. Drop the second note from the top. That is it.","speaker":"jajii","startBeat":24,"durationBeats":4},{"ja":"G7 でも同じじゃ。まずはクローズド。","en":"Same for G7. First, closed.","speaker":"jajii","startBeat":28,"durationBeats":4},{"ja":"上から2番目の B を落とす。","en":"Drop the B, the second note from the top.","speaker":"jajii","startBeat":32,"durationBeats":4},{"ja":"これが G7 の Drop2。B、F、A、E。","en":"This is G7 Drop 2. B, F, A, E.","speaker":"jajii","startBeat":36,"durationBeats":4},{"ja":"CM7 でも同じ。まずはクローズド。","en":"Same for CM7. First, closed.","speaker":"jajii","startBeat":40,"durationBeats":4},{"ja":"上から2番目の B を下に落とす。","en":"Drop the B, the second note from the top.","speaker":"jajii","startBeat":44,"durationBeats":4},{"ja":"これが CM7 の Drop2。B、E、G、D。","en":"This is CM7 Drop 2. B, E, G, D.","speaker":"jajii","startBeat":48,"durationBeats":4},{"ja":"ここからが大事じゃ。進行で見るぞい。","en":"Now the important part. Watch the progression.","speaker":"jajii","startBeat":52,"durationBeats":4},{"ja":"Dm7 から G7。","en":"Dm7 to G7.","speaker":"fai","startBeat":56,"durationBeats":4},{"ja":"左手だけ見ろ。C から B に半音下がるだけじゃ。","en":"Watch only the left hand. C moves down to B.","speaker":"jajii","startBeat":60,"durationBeats":4},{"ja":"C、B。ここだけで II-V の感じが出る。","en":"C, B. This alone gives the II-V sound.","speaker":"jajii","startBeat":64,"durationBeats":4},{"ja":"次は G7 から CM7。","en":"Next, G7 to CM7.","speaker":"fai","startBeat":68,"durationBeats":4},{"ja":"左手の B はキープじゃ。","en":"Keep the left-hand B.","speaker":"jajii","startBeat":72,"durationBeats":4},{"ja":"右手の3声が、スケール上に下がる。F-A-E から E-G-D。","en":"The three right-hand notes move down the scale. F-A-E to E-G-D.","speaker":"jajii","startBeat":76,"durationBeats":4},{"ja":"つまり、全部を動かそうとしなくていい。動く場所だけ見ればよい。","en":"So you do not need to move everything. Watch only the moving parts.","speaker":"jajii","startBeat":80,"durationBeats":4},{"ja":"流れで弾くぞい。Dm7。","en":"Now in flow. Dm7.","speaker":"jajii","startBeat":84,"durationBeats":4},{"ja":"G7。左手が半音下がる。","en":"G7. The left hand moves down a half step.","speaker":"jajii","startBeat":88,"durationBeats":4},{"ja":"CM7。左手はキープ、右手が下がる。","en":"CM7. Keep the left hand, move the right hand down.","speaker":"jajii","startBeat":92,"durationBeats":4},{"ja":"もう一度じゃ。見る場所は少ない。","en":"Again. There are only a few things to watch.","speaker":"jajii","startBeat":96,"durationBeats":4},{"ja":"Dm7、G7。","en":"Dm7, G7.","speaker":"fai","startBeat":100,"durationBeats":4},{"ja":"CM7。","en":"CM7.","speaker":"fai","startBeat":104,"durationBeats":4},{"ja":"最後にもう一回。形を耳と手に焼きつけるんじゃ。","en":"One last time. Burn the shape into your ears and hands.","speaker":"jajii","startBeat":108,"durationBeats":4},{"ja":"Drop2は、難しい名前ではない。上から2番目を落とした形じゃ。","en":"Drop 2 is not a difficult name. It is the shape made by dropping the second note from the top.","speaker":"jajii","startBeat":112,"durationBeats":4},{"ja":"II-V-Iでは、左手と右手の動きが少ない。そこがこの形の強みじゃ。","en":"In a II-V-I, the left and right hands move very little. That is the strength of this shape.","speaker":"jajii","startBeat":116,"durationBeats":4},{"ja":"まずはこの3つだけ覚えろ。Dm7、G7、CM7じゃ。","en":"For now, learn only these three. Dm7, G7, CM7.","speaker":"jajii","startBeat":120,"durationBeats":4}],"endHoldBeats":4},{"type":"finish"}],"finish":{"showCta":true}}'::jsonb,
  updated_at = now()
WHERE id = 'thvi-demo-b1-q1';

